38	// Stream `gitnexus analyze` with optional flags. onLine is called for each
39	// stdout/stderr line. Resolves with { code }.
40	export function analyze(workdir, opts = {}) {
41	  // Note: gitnexus 1.6+ has embeddings OFF by default — pass `--embeddings` to
42	  // opt in. We default to OFF (cheap, no API key needed). `--skip-agents-md`
43	  // is on by default to avoid mutating the user's repo.
44	  const args = ['analyze'];
45	  if (opts.force) args.push('--force');
46	  if (opts.embeddings) args.push('--embeddings');
47	  if (opts.skipAgentsMd !== false) args.push('--skip-agents-md');
48	  return new Promise((resolve, reject) => {
49	    const child = spawnNpx(args, workdir);
50	    let timer;
51	    const onLine = opts.onLine || (() => {});
52	    const reset = () => {
53	      if (timer) clearTimeout(timer);
54	      timer = setTimeout(() => {
