NN38FA5g","isError":false,"content":"1	// GitNexus integration — wraps the `gitnexus` CLI and its MCP stdio server.
2	// We intentionally do NOT take gitnexus as an npm dependency: the CLI is
3	// invoked through `npx -y gitnexus@latest <args>`, so the console works on
4	// any machine without bloating package.json. MCP requests use the standard
5	// LSP-style `Content-Length` framing.
6	import { spawn } from 'node:child_process';
7	
8	const CLI_PKG = 'gitnexus@latest';
9	const NPX = process.platform === 'win32' ? 'npx.cmd' : 'npx';
10	
11	let _availability = null;
12	
13	export async function isAvailable() {
14	  if (_availability) return _availability;
15	  try {
16	    const { stdout, code } = await runCli(['--version'], { timeoutMs: 30_000 });
17	    if (code === 0) {
18	      _availability = { available: true, version: stdout.trim() };
19	    } else {
20	      _availability = { available: false, error: 'gitnexus --version 退出码 ' + code };
21	    }
22	  } catch (e) {
23	    _availability = { available: false, error: e.message };
24	  }
25	  return _availability;
26	}
