28	// `gitnexus status` in current repo. Returns { indexed, raw, summary }.
29	export async function getStatus(workdir) {
30	  const { stdout, stderr, code } = await runCli(['status'], { cwd: workdir, timeoutMs: 30_000 });
31	  const raw = (stdout + (stderr ? '\n' + stderr : '')).trim();
32	  if (code !== 0) {
33	    return { indexed: false, raw, summary: { error: raw || `exit ${code}` } };
34	  }
35	  return { indexed: detectIndexed(raw), raw, summary: parseStatus(raw) };
36	}
