104	// Convenience: function/method call graph. GitNexus models all relationships
105	// via a single `CodeRelation` REL with `r.type` discriminator (CALLS, DEFINES,
106	// MEMBER_OF, …). We only follow `r.type = 'CALLS'` between callable nodes.
107	export async function getCallGraph(workdir, { limit = 300 } = {}) {
108	  const cap = Math.max(1, Math.min(2000, limit | 0));
109	  const q = `MATCH (a)-[r:CodeRelation]->(b)
110	WHERE r.type = 'CALLS'
111	RETURN a.name AS fromName, a.filePath AS fromFile,
112	       b.name AS toName, b.filePath AS toFile
113	LIMIT ${cap}`;
114	  const rows = await cypher(workdir, q);
115	  return shapeCallGraph(rows);
116	}
