186	// Stand up an MCP stdio session, run an async sender, then close.
187	async function mcpRpc(workdir, timeoutMs, fn) {
188	  const child = spawnNpx(['mcp'], workdir, { withStdin: true });
189	  let nextId = 1;
190	  const pending = new Map(); // id → { resolve, reject }
191	  let buf = Buffer.alloc(0);
192	  let closed = false;
193	  let stderrBuf = '';
194	
195	  const killTimer = setTimeout(() => {
196	    closed = true;
197	    try { child.kill('SIGTERM'); } catch {}
198	    for (const { reject } of pending.values()) reject(new Error('MCP 调用超时'));
199	    pending.clear();
200	  }, timeoutMs);
201	
202	  child.stderr.on('data', (b) => { stderrBuf += b.toString(); if (stderrBuf.length > 16_000) stderrBuf = stderrBuf.slice(-8_000); });
203	
204	  child.stdout.on('data', (chunk) => {
205	    buf = Buffer.concat([buf, chunk]);
206	    while (true) {
207	      const headerEnd = buf.indexOf('\r\n\r\n');
208	      if (headerEnd === -1) break;
209	      const header = buf.slice(0, headerEnd).toString('utf8');
210	      const m = header.match(/Content-Length:\s*(\d+)/i);
211	      if (!m) {
212	        // Drop malformed header
213	        buf = buf.slice(headerEnd + 4);
214	        continue;
215	      }
216	      const len = parseInt(m[1], 10);
217	      const total = headerEnd + 4 + len;
218	      if (buf.length < total) break;
219	      const body = buf.slice(headerEnd + 4, total).toString('utf8');
220	      buf = buf.slice(total);
221	      try {
222	        const msg = JSON.parse(body);
223	        if (msg.id != null && pending.has(msg.id)) {
224	          const { resolve, reject } = pending.get(msg.id);
225	          pending.delete(msg.id);
226	          if (msg.error) reject(new Error(msg.error.message || 'MCP error'));
227	          else resolve(msg.result);
228	        }
229	      } catch {}
230	    }
231	  });
232	
233	  child.on('error', () => {
234	    closed = true;
235	    for (const { reject } of pending.values()) reject(new Error('MCP 进程异常'));
236	    pending.clear();
237	  });
238	  child.on('close', () => {
239	    closed = true;
240	    for (const { reject } of pending.values()) reject(new Error('MCP 提前关闭：' + stderrBuf.trim().slice(-400)));
241	    pending.clear();
242	  });
243	
244	  function send(obj) {
245	    const body = JSON.stringify(obj);
246	    const header = `Content-Length: ${Buffer.byteLength(body, 'utf8')}\r\n\r\n`;
247	    child.stdin.write(header + body);
248	  }
249	
250	  function rpc(method, params) {
251	    return new Promise((resolve, reject) => {
252	      if (closed) return reject(new Error('MCP 已关闭'));
253	      const id = nextId++;
254	      pending.set(id, { resolve, reject });
255	      send({ jsonrpc: '2.0', id, method, params });
256	    });
257	  }
258	
259	  try {
260	    await rpc('initialize', {
261	      protocolVersion: '2024-11-05',
262	      capabilities: {},
263	      clientInfo: { name: 'claude-code-console', version: '0.1.0' },
264	    });
265	    send({ jsonrpc: '2.0', method: 'notifications/initialized', params: {} });
266	    return await fn(rpc);
267	  } finally {
268	    clearTimeout(killTimer);
269	    try { child.stdin.end(); } catch {}
270	    try { child.kill('SIGTERM'); } catch {}
271	  }
272	}
