274	// Pull JSON / text out of an MCP tool result. Tools return content[] of
275	// `{type:'text', text}` blocks; many wrap a JSON payload as text.
276	function parseToolText(result) {
277	  if (!result) return null;
278	  const content = Array.isArray(result.content) ? result.content : [];
279	  const texts = content.filter((c) => c && c.type === 'text').map((c) => c.text);
280	  const joined = texts.join('\n');
281	  if (!joined.trim()) return result;
282	  // GitNexus appends a `\n---\n**Next:** …` hint after every tool payload.
283	  // Strip it before attempting JSON.parse.
284	  const sep = joined.indexOf('\n---\n');
285	  const head = sep === -1 ? joined : joined.slice(0, sep);
286	  try { return JSON.parse(head); } catch { return head; }
287	}
