310	// Parse the GitHub-flavored markdown table that GitNexus's `cypher` tool
311	// returns. Format:  `| col1 | col2 |\n| --- | --- |\n| v1 | v2 |\n…`
312	// Cells may contain JSON-encoded scalars (e.g. `"foo"`, `[1,2]`); we try
313	// JSON.parse first and fall back to the raw string.
314	function parseMarkdownTable(md) {
315	  const lines = md.split('\n').map((l) => l.trim()).filter(Boolean);
316	  if (lines.length < 2) return [];
317	  const header = splitMdRow(lines[0]);
318	  // lines[1] is the divider `| --- | --- |`
319	  const out = [];
320	  for (let i = 2; i < lines.length; i++) {
321	    const cells = splitMdRow(lines[i]);
322	    if (cells.length === 0) continue;
323	    const row = {};
324	    for (let c = 0; c < header.length; c++) {
325	      row[header[c]] = decodeMdCell(cells[c] ?? '');
326	    }
327	    out.push(row);
328	  }
329	  return out;
330	}
331	
332	function splitMdRow(line) {
333	  // Strip leading/trailing pipes, split, trim cells.
334	  const trimmed = line.replace(/^\||\|$/g, '');
335	  return trimmed.split('|').map((c) => c.trim());
336	}
337	
338	function decodeMdCell(cell) {
339	  if (cell === '' || cell === 'null') return null;
340	  // GitNexus escapes inner quotes (\"); try JSON parse first.
341	  try { return JSON.parse(cell); } catch {}
342	  return cell;
343	}
344	
345	function detectIndexed(raw) {
346	  if (!raw) return false;
347	  if (/not\s+indexed|no\s+index|repository\s+not\s+indexed/i.test(raw)) return false;
348	  return /^Indexed[:\s]/im.test(raw)
349	    || /up[-\s]?to[-\s]?date|stale|out[-\s]?of[-\s]?date/i.test(raw);
350	}
351	
352	function parseStatus(raw) {
353	  const out = {};
354	  const grab = (re, key) => {
355	    const m = raw.match(re);
356	    if (m) out[key] = m[1].trim();
357	  };
358	  const num = (re, key) => {
359	    const m = raw.match(re);
360	    if (m) out[key] = parseInt(m[1].replace(/[,_]/g, ''), 10);
361	  };
362	  // Format used by gitnexus 1.6.x:
363	  //   Repository: /path
364	  //   Indexed: 5/15/2026, 4:02:07 PM
365	  //   Indexed commit: <sha>
366	  //   Current commit: <sha>
367	  //   Status: ✅ up-to-date | ⚠ stale | ...
368	  grab(/^Repository[:\s]+(.+)$/im, 'repo');
369	  grab(/^Indexed[:\s]+(.+)$/im, 'lastIndexed');
370	  grab(/^Indexed commit[:\s]+([0-9a-f]+)/im, 'indexedCommit');
371	  grab(/^Current commit[:\s]+([0-9a-f]+)/im, 'currentCommit');
372	  grab(/^Status[:\s]+(.+)$/im, 'statusLine');
373	  // Best-effort numeric fields if a future version adds them:
374	  num(/files?\s*[:=]\s*([\d,_]+)/i, 'files');
375	  num(/symbols?\s*[:=]\s*([\d,_]+)/i, 'symbols');
376	  num(/nodes?\s*[:=]\s*([\d,_]+)/i, 'nodes');
377	  num(/edges?\s*[:=]\s*([\d,_]+)/i, 'edges');
378	  if (out.statusLine && /stale|out[-\s]?of[-\s]?date/i.test(out.statusLine)) out.stale = true;
379	  if (out.indexedCommit && out.currentCommit && out.indexedCommit !== out.currentCommit) out.stale = true;
380	  return out;
381	}
