1	// GitNexus integration — wraps the `gitnexus` CLI and its MCP stdio server.
2	// We intentionally do NOT take gitnexus as an npm dependency: the CLI is
3	// invoked through `npx -y gitnexus@latest <args>`, so the console works on
4	// any machine without bloating package.json. MCP requests use the standard
5	// LSP-style `Content-Length` framing.
6	import { spawn } from 'node:child_process';
7	
8	const CLI_PKG = 'gitnexus@latest';
9	const NPX = process.platform === 'win32' ? 'npx.cmd' : 'npx';
10	
11	let _availability = null;
12	
13	export async function isAvailable() {
14	  if (_availability) return _availability;
15	  try {
16	    const { stdout, code } = await runCli(['--version'], { timeoutMs: 30_000 });
17	    if (code === 0) {
18	      _availability = { available: true, version: stdout.trim() };
19	    } else {
20	      _availability = { available: false, error: 'gitnexus --version 退出码 ' + code };
21	    }
22	  } catch (e) {
23	    _availability = { available: false, error: e.message };
24	  }
25	  return _availability;
26	}
27	
28	// `gitnexus status` in current repo. Returns { indexed, raw, summary }.
29	export async function getStatus(workdir) {
30	  const { stdout, stderr, code } = await runCli(['status'], { cwd: workdir, timeoutMs: 30_000 });
31	  const raw = (stdout + (stderr ? '\n' + stderr : '')).trim();
32	  if (code !== 0) {
33	    return { indexed: false, raw, summary: { error: raw || `exit ${code}` } };
34	  }
35	  return { indexed: detectIndexed(raw), raw, summary: parseStatus(raw) };
36	}
37	
38	// Stream `gitnexus analyze` with optional flags. onLine is called for each
39	// stdout/stderr line. Resolves with { code }.
40	export function analyze(workdir, opts = {}) {
41	  // Note: gitnexus 1.6+ has embeddings OFF by default — pass `--embeddings` to
42	  // opt in. We default to OFF (cheap, no API key needed). `--skip-agents-md`
43	  // is on by default to avoid mutating the user's repo.
44	  const args = ['analyze'];
45	  if (opts.force) args.push('--force');
46	  if (opts.embeddings) args.push('--embeddings');
47	  if (opts.skipAgentsMd !== false) args.push('--skip-agents-md');
48	  return new Promise((resolve, reject) => {
49	    const child = spawnNpx(args, workdir);
50	    let timer;
51	    const onLine = opts.onLine || (() => {});
52	    const reset = () => {
53	      if (timer) clearTimeout(timer);
54	      timer = setTimeout(() => {
55	        try { child.kill('SIGTERM'); } catch {}
56	      }, opts.idleTimeoutMs || 600_000);
57	    };
58	    reset();
59	    pipeLines(child.stdout, (line) => { onLine({ stream: 'stdout', line }); reset(); });
60	    pipeLines(child.stderr, (line) => { onLine({ stream: 'stderr', line }); reset(); });
61	    child.on('error', (e) => { if (timer) clearTimeout(timer); reject(e); });
62	    child.on('close', (code) => {
63	      if (timer) clearTimeout(timer);
64	      resolve({ code: code ?? -1 });
65	    });
66	  });
67	}
68	
69	// Call a single MCP tool, then close the server. For read-mostly UI use, this
70	// 1-shot policy keeps the implementation simple at the cost of a ~1-2s cold
71	// start per call. Returns the raw JSON-RPC `result` payload.
72	export function callTool(workdir, name, args = {}, opts = {}) {
73	  return mcpRpc(workdir, opts.timeoutMs || 30_000, async (rpc) => {
74	    return await rpc('tools/call', { name, arguments: args });
75	  });
76	}
77	
78	// Read a Resource. `uri` like `gitnexus://repo/<name>/processes`.
79	export function readResource(workdir, uri, opts = {}) {
80	  return mcpRpc(workdir, opts.timeoutMs || 30_000, async (rpc) => {
81	    return await rpc('resources/read', { uri });
82	  });
83	}
84	
85	// List indexed repos via the `list_repos` tool.
86	export async function listRepos(workdir, opts = {}) {
87	  const result = await callTool(workdir, 'list_repos', {}, opts);
88	  return parseToolText(result);
89	}
90	
91	// Run a Cypher query against the repo's knowledge graph (Kuzu / LadybugDB).
92	// The MCP `cypher` tool returns either { markdown, row_count } or { error };
93	// we parse the markdown into row objects so callers get structured data.
94	export async function cypher(workdir, query, params = {}, opts = {}) {
95	  const result = await callTool(workdir, 'cypher', { query, params }, opts);
96	  const payload = parseToolText(result);
97	  if (payload && typeof payload === 'object') {
98	    if (payload.error) throw new Error('cypher: ' + payload.error);
99	    if (typeof payload.markdown === 'string') return parseMarkdownTable(payload.markdown);
100	  }
101	  return payload;
102	}
103	
104	// Convenience: function/method call graph. GitNexus models all relationships
105	// via a single `CodeRelation` REL with `r.type` discriminator (CALLS, DEFINES,
106	// MEMBER_OF, …). We only follow `r.type = 'CALLS'` between callable nodes.
107	export async function getCallGraph(workdir, { limit = 300 } = {}) {
108	  const cap = Math.max(1, Math.min(2000, limit | 0));
109	  const q = `MATCH (a)-[r:CodeRelation]->(b)
110	WHERE r.type = 'CALLS'
111	RETURN a.name AS fromName, a.filePath AS fromFile,
112	       b.name AS toName, b.filePath AS toFile
113	LIMIT ${cap}`;
114	  const rows = await cypher(workdir, q);
115	  return shapeCallGraph(rows);
116	}
117	
118	// Convenience: processes (execution flows) with step counts. Process nodes use
119	// `label` (not `name`) and carry an authoritative `stepCount` already.
120	export async function getProcesses(workdir, { limit = 100 } = {}) {
121	  const cap = Math.max(1, Math.min(500, limit | 0));
