13	export async function isAvailable() {
14	  if (_availability) return _availability;
15	  try {
16	    const { stdout, code } = await runCli(['--version'], { timeoutMs: 30_000 });
17	    if (code === 0) {
18	      _availability = { available: true, version: stdout.trim() };
19	    } else {
20	      _availability = { available: false, error: 'gitnexus --version 退出码 ' + code };
21	    }
22	  } catch (e) {
23	    _availability = { available: false, error: e.message };
24	  }
25	  return _availability;
26	}
