69	// Call a single MCP tool, then close the server. For read-mostly UI use, this
70	// 1-shot policy keeps the implementation simple at the cost of a ~1-2s cold
71	// start per call. Returns the raw JSON-RPC `result` payload.
72	export function callTool(workdir, name, args = {}, opts = {}) {
73	  return mcpRpc(workdir, opts.timeoutMs || 30_000, async (rpc) => {
74	    return await rpc('tools/call', { name, arguments: args });
75	  });
76	}
