118	// Convenience: processes (execution flows) with step counts. Process nodes use
119	// `label` (not `name`) and carry an authoritative `stepCount` already.
120	export async function getProcesses(workdir, { limit = 100 } = {}) {
121	  const cap = Math.max(1, Math.min(500, limit | 0));
122	  const q = `MATCH (p:Process)
123	RETURN p.label AS name, p.id AS id, p.stepCount AS steps, p.processType AS kind
