289	function shapeCallGraph(data) {
290	  const rows = Array.isArray(data) ? data : [];
291	  const nodeMap = new Map();
292	  const edges = [];
293	  const ensure = (name, file, kind) => {
294	    const id = `${file || ''}::${name || '?'}`;
295	    if (!nodeMap.has(id)) {
296	      nodeMap.set(id, { id, name: name || id, file: file || '', kind: kind || '', inDeg: 0, outDeg: 0 });
297	    }
298	    return nodeMap.get(id);
299	  };
300	  for (const r of rows) {
301	    if (!r.fromName || !r.toName) continue;
302	    const a = ensure(r.fromName, r.fromFile, r.fromKind);
303	    const b = ensure(r.toName, r.toFile, r.toKind);
304	    a.outDeg++; b.inDeg++;
305	    edges.push({ from: a.id, to: b.id });
306	  }
307	  return { nodes: Array.from(nodeMap.values()), edges, raw: rows.length };
308	}
