91	// Run a Cypher query against the repo's knowledge graph (Kuzu / LadybugDB).
92	// The MCP `cypher` tool returns either { markdown, row_count } or { error };
93	// we parse the markdown into row objects so callers get structured data.
94	export async function cypher(workdir, query, params = {}, opts = {}) {
95	  const result = await callTool(workdir, 'cypher', { query, params }, opts);
96	  const payload = parseToolText(result);
97	  if (payload && typeof payload === 'object') {
98	    if (payload.error) throw new Error('cypher: ' + payload.error);
99	    if (typeof payload.markdown === 'string') return parseMarkdownTable(payload.markdown);
100	  }
101	  return payload;
102	}
