129	// Convenience: blast radius for a symbol name. Falls back to `query` when
130	// `impact` rejects ambiguous targets.
131	export async function getImpact(workdir, symbol) {
132	  try {
133	    return await callTool(workdir, 'impact', { target: symbol });
134	  } catch (e) {
135	    return await callTool(workdir, 'context', { symbol });
