141	function spawnNpx(args, cwd, { withStdin = false } = {}) {
142	  return spawn(NPX, ['-y', CLI_PKG, ...args], {
143	    cwd,
144	    env: { ...process.env, FORCE_COLOR: '0', NO_COLOR: '1' },
145	    stdio: [withStdin ? 'pipe' : 'ignore', 'pipe', 'pipe'],
146	  });
147	}
148	
149	function runCli(args, opts = {}) {
150	  return new Promise((resolve, reject) => {
151	    const child = spawn(NPX, ['-y', CLI_PKG, ...args], {
152	      cwd: opts.cwd,
153	      env: { ...process.env, FORCE_COLOR: '0', NO_COLOR: '1' },
154	      stdio: ['ignore', 'pipe', 'pipe'],
155	    });
156	    let stdout = '', stderr = '';
157	    const timer = setTimeout(() => {
158	      try { child.kill('SIGTERM'); } catch {}
159	    }, opts.timeoutMs || 60_000);
160	    child.stdout.on('data', (b) => (stdout += b.toString()));
161	    child.stderr.on('data', (b) => (stderr += b.toString()));
162	    child.on('error', (e) => { clearTimeout(timer); reject(e); });
163	    child.on('close', (code) => {
164	      clearTimeout(timer);
165	      resolve({ stdout, stderr, code: code ?? -1 });
166	    });
167	  });
168	}
