170	function pipeLines(stream, cb) {
171	  let buf = '';
172	  stream.on('data', (chunk) => {
173	    buf += chunk.toString();
174	    let i;
175	    while ((i = buf.indexOf('\n')) !== -1) {
176	      const line = buf.slice(0, i).replace(/\r$/, '');
177	      buf = buf.slice(i + 1);
178	      if (line.length) cb(line);
179	    }
180	  });
181	  stream.on('end', () => {
182	    if (buf.length) cb(buf);
183	  });
184	}
