1	// Policy engine — decides how Claude tool requests should be handled.
2	// Each session carries a Policy. Policies map to Claude Code's --permission-mode
3	// AND to a set of finer-grained rules we evaluate ourselves on tool_use events
4	// for visualization and auditing.
5	
6	export const PERMISSION_MODES = ['default', 'acceptEdits', 'auto', 'bypassPermissions', 'plan'];
7	
8	export const PRESET_POLICIES = {
9	  conservative: {
10	    id: 'conservative',
11	    name: '保守模式',
12	    description: '默认权限模式，所有工具调用都标记为需要人工确认',
13	    permissionMode: 'default',
14	    rules: [
15	      { match: 'tool:Bash', decision: 'manual', reason: '命令执行需要人工确认' },
16	      { match: 'tool:Write', decision: 'manual', reason: '写入新文件需要确认' },
17	      { match: 'tool:Edit', decision: 'manual', reason: '编辑文件需要确认' },
18	      { match: 'tool:*', decision: 'manual', reason: '默认人工确认' },
19	    ],
20	  },
21	  balanced: {
22	    id: 'balanced',
23	    name: '平衡模式（推荐）',
24	    description: '自动允许编辑当前项目内的文件，命令与跨目录操作转人工',
25	    permissionMode: 'acceptEdits',
26	    rules: [
27	      { match: 'path:outside-workdir', decision: 'manual', reason: '操作目标在工作目录之外' },
28	      { match: 'tool:Bash:rm', decision: 'manual', reason: '涉及删除命令' },
29	      { match: 'tool:Bash:git push', decision: 'manual', reason: '涉及推送远端仓库' },
30	      { match: 'tool:Bash:git reset --hard', decision: 'manual', reason: '可能丢失工作' },
31	      { match: 'tool:Bash', decision: 'auto', reason: '一般命令在工作目录内自动允许' },
32	      { match: 'tool:Edit', decision: 'auto', reason: '当前项目内编辑自动允许' },
33	      { match: 'tool:Write', decision: 'auto', reason: '当前项目内写入自动允许' },
34	      { match: 'tool:Read', decision: 'auto', reason: '只读操作自动允许' },
35	      { match: 'tool:Grep', decision: 'auto', reason: '搜索操作自动允许' },
36	      { match: 'tool:Glob', decision: 'auto', reason: '搜索操作自动允许' },
37	      { match: 'tool:*', decision: 'auto', reason: '默认自动允许（受 acceptEdits 模式约束）' },
38	    ],
39	  },
40	  aggressive: {
41	    id: 'aggressive',
42	    name: '激进模式',
43	    description: '跳过全部权限检查（仅在受信目录使用）',
44	    permissionMode: 'bypassPermissions',
45	    rules: [
46	      { match: 'tool:*', decision: 'auto', reason: '已开启 bypassPermissions，全部跳过' },
47	    ],
48	  },
49	  planOnly: {
50	    id: 'planOnly',
51	    name: '只计划',
52	    description: '只生成计划，不允许执行修改类工具',
53	    permissionMode: 'plan',
54	    rules: [
55	      { match: 'tool:Edit', decision: 'reject', reason: '当前为只计划模式' },
56	      { match: 'tool:Write', decision: 'reject', reason: '当前为只计划模式' },
57	      { match: 'tool:Bash', decision: 'reject', reason: '当前为只计划模式' },
