63	export function getPolicy(id) {
64	  return PRESET_POLICIES[id] || PRESET_POLICIES.balanced;
65	}
66	
67	// Evaluate a tool_use event against a policy.
68	// Returns { decision: 'auto'|'manual'|'reject', reason, rule }
69	export function evaluateToolUse(policy, toolUse, ctx = {}) {
70	  const toolName = toolUse.name || toolUse.tool || 'Unknown';
71	  const input = toolUse.input || {};
72	  const workdir = ctx.workdir;
73	
74	  for (const rule of policy.rules) {
75	    const m = rule.match;
76	    if (!m.startsWith('tool:') && !m.startsWith('path:')) continue;
77	
78	    if (m === 'path:outside-workdir' && workdir) {
79	      const targets = collectPathTargets(input);
80	      const outside = targets.find((p) => !isInside(p, workdir));
81	      if (outside) {
82	        return { decision: rule.decision, reason: rule.reason + `（${outside}）`, rule };
83	      }
84	      continue;
85	    }
86	
87	    if (m.startsWith('tool:')) {
88	      const parts = m.slice('tool:'.length).split(':');
89	      const ruleTool = parts[0];
90	      const subPattern = parts.slice(1).join(':');
91	
92	      if (ruleTool !== '*' && ruleTool !== toolName) continue;
93	
94	      if (subPattern) {
95	        // Try matching against bash command
96	        const cmd = input.command || input.cmd || '';
97	        if (!cmd.toLowerCase().includes(subPattern.toLowerCase())) continue;
98	      }
99	      return { decision: rule.decision, reason: rule.reason, rule };
100	    }
101	  }
102	  return { decision: 'manual', reason: '没有命中规则，转人工确认', rule: null };
103	}
104	
105	function collectPathTargets(input) {
106	  const targets = [];
107	  for (const key of ['file_path', 'path', 'notebook_path', 'output_file']) {
108	    if (typeof input[key] === 'string') targets.push(input[key]);
109	  }
110	  return targets;
111	}
112	
113	function isInside(target, workdir) {
114	  if (!target) return true;
115	  let abs = target;
116	  if (!abs.startsWith('/')) abs = workdir.replace(/\/$/, '') + '/' + abs;
117	  const wd = workdir.replace(/\/$/, '');
118	  // Tolerate macOS symlink prefix /tmp <-> /private/tmp
119	  const candidates = [wd];
120	  if (wd.startsWith('/private/')) candidates.push(wd.slice('/private'.length));
121	  else candidates.push('/private' + wd);
122	  return candidates.some((c) => abs === c || abs.startsWith(c + '/'));
123	}
