1	// Claude Code Console — single-process Node server.
2	// Serves a static UI (public/), exposes a small JSON API, and broadcasts
3	// session events over Server-Sent Events.
4	import http from 'node:http';
5	import fs from 'node:fs';
6	import path from 'node:path';
7	import { fileURLToPath } from 'node:url';
8	
9	import { SessionManager } from './src/sessionManager.js';
10	import { SessionStore } from './src/sessionStore.js';
11	import { PRESET_POLICIES, getPolicy } from './src/policyEngine.js';
12	import { scanStructure, annotateChanges } from './src/structure.js';
13	import { buildDesignGraph } from './src/designGraph.js';
14	import { buildCodeMap } from './src/codeMap.js';
15	import * as gitnexus from './src/gitnexus.js';
16	
17	const __dirname = path.dirname(fileURLToPath(import.meta.url));
18	const PUBLIC_DIR = path.join(__dirname, 'public');
19	const PORT = parseInt(process.env.PORT || '4477', 10);
20	
21	const DATA_DIR =
22	  process.env.CLAUDE_CONSOLE_DATA || path.join(__dirname, '.claude-console', 'sessions');
23	const store = new SessionStore({ dir: DATA_DIR });
24	const manager = new SessionManager({ store });
25	for (const persisted of store.loadAll()) {
26	  try {
27	    manager.hydrate(persisted);
28	  } catch (e) {
29	    console.error(`[startup] failed to hydrate ${persisted?.id}:`, e.message);
30	  }
31	}
32	const sseClients = new Set();
33	
34	manager.on('session:event', (payload) => broadcast('event', payload));
35	manager.on('session:updated', (payload) => broadcast('session:updated', payload));
36	manager.on('session:created', (payload) => broadcast('session:created', payload));
37	manager.on('session:removed', (payload) => broadcast('session:removed', payload));
38	
39	function broadcast(kind, data) {
40	  const line = `event: ${kind}\ndata: ${JSON.stringify(data)}\n\n`;
41	  for (const res of sseClients) {
42	    try {
43	      res.write(line);
44	    } catch {
45	      sseClients.delete(res);
46	    }
47	  }
48	}
49	
50	const MIME = {
51	  '.html': 'text/html; charset=utf-8',
52	  '.js': 'application/javascript; charset=utf-8',
53	  '.css': 'text/css; charset=utf-8',
54	  '.svg': 'image/svg+xml',
55	  '.ico': 'image/x-icon',
56	  '.png': 'image/png',
57	  '.json': 'application/json; charset=utf-8',
58	};
59	
60	const server = http.createServer(async (req, res) => {
61	  const reqUrl = new URL(req.url, `http://${req.headers.host || 'localhost'}`);
62	  const pathname = reqUrl.pathname;
63	  const parsed = { query: Object.fromEntries(reqUrl.searchParams) };
64	
65	  // CORS friendliness for local tools
66	  res.setHeader('Access-Control-Allow-Origin', '*');
67	  res.setHeader('Access-Control-Allow-Methods', 'GET, POST, DELETE, OPTIONS');
68	  res.setHeader('Access-Control-Allow-Headers', 'Content-Type');
69	  if (req.method === 'OPTIONS') {
70	    res.writeHead(204);
71	    res.end();
72	    return;
73	  }
74	
75	  try {
76	    if (pathname === '/api/health') return json(res, 200, { ok: true });
77	    if (pathname === '/api/gitnexus/health' && req.method === 'GET') {
78	      const info = await gitnexus.isAvailable();
79	      return json(res, 200, info);
80	    }
81	    if (pathname === '/api/policies') return json(res, 200, { policies: PRESET_POLICIES });
82	    if (pathname === '/api/sessions' && req.method === 'GET')
83	      return json(res, 200, { sessions: manager.list() });
84	    if (pathname === '/api/sessions' && req.method === 'POST') {
85	      const body = await readJson(req);
86	      const s = manager.create(body);
87	      return json(res, 201, { session: s.summary() });
88	    }
89	    if (pathname === '/api/cwd' && req.method === 'GET')
90	      return json(res, 200, { cwd: process.cwd() });
91	
92	    if (pathname === '/api/events' && req.method === 'GET') {
93	      res.writeHead(200, {
94	        'Content-Type': 'text/event-stream; charset=utf-8',
95	        'Cache-Control': 'no-cache',
96	        Connection: 'keep-alive',
97	        'X-Accel-Buffering': 'no',
98	      });
99	      res.write(`event: hello\ndata: ${JSON.stringify({ ts: Date.now() })}\n\n`);
100	      sseClients.add(res);
101	      const ping = setInterval(() => {
102	        try {
103	          res.write(`event: ping\ndata: {}\n\n`);
104	        } catch {}
105	      }, 25_000);
106	      req.on('close', () => {
107	        clearInterval(ping);
108	        sseClients.delete(res);
109	      });
110	      return;
111	    }
112	
113	    // /api/sessions/:id...
114	    const match = pathname.match(/^\/api\/sessions\/([^/]+)(\/.*)?$/);
115	    if (match) {
116	      const id = match[1];
117	      const rest = match[2] || '';
118	      const session = manager.get(id);
119	      if (!session) return json(res, 404, { error: '会话不存在' });
120	
121	      if (rest === '' || rest === '/') {
122	        if (req.method === 'GET') {
123	          return json(res, 200, {
124	            session: session.summary(),
125	            policy: getPolicy(session.policyId),
126	            turns: session.turns,
127	            events: session.events,
128	            tools: session.tools,
129	            changes: session.changes,
130	            pendingApprovals: Array.from(session.pendingApprovals.values()),
131	          });
132	        }
133	        if (req.method === 'DELETE') {
134	          manager.remove(id);
135	          return json(res, 200, { ok: true });
136	        }
137	      }
138	
139	      if (rest === '/prompt' && req.method === 'POST') {
140	        const body = await readJson(req);
141	        if (!body.prompt || typeof body.prompt !== 'string')
142	          return json(res, 400, { error: 'prompt 必填' });
143	        try {
144	          const turn = await session.sendPrompt(body.prompt);
145	          return json(res, 202, { turn });
146	        } catch (e) {
147	          return json(res, 400, { error: e.message });
148	        }
149	      }
150	
151	      if (rest === '/cancel' && req.method === 'POST') {
152	        session.cancel();
153	        return json(res, 200, { ok: true });
154	      }
155	
156	      if (rest === '/policy' && req.method === 'POST') {
157	        const body = await readJson(req);
158	        session.setPolicy(body.policyId);
159	        return json(res, 200, { ok: true });
160	      }
161	
162	      if (rest === '/structure' && req.method === 'GET') {
163	        const tree = scanStructure(session.workdir);
164	        annotateChanges(tree, session.lastChangeMap);
165	        return json(res, 200, { tree });
166	      }
167	
168	      if (rest === '/code-map' && req.method === 'GET') {
169	        try {
170	          const map = buildCodeMap(session.workdir);
171	          // Annotate symbols with last-change info using session.lastChangeMap
172	          const changeMap = session.lastChangeMap || {};
173	          for (const s of map.symbols) {
174	            const c = changeMap[s.relPath];
175	            if (c) s.lastChange = c;
176	          }
177	          for (const f of map.files) {
178	            const c = changeMap[f.relPath];
179	            if (c) f.lastChange = c;
180	          }
181	          return json(res, 200, { map });
182	        } catch (e) {
183	          return json(res, 500, { error: e.message });
184	        }
185	      }
186	
187	      if (rest === '/design-graph' && req.method === 'GET') {
188	        const type = parsed.query.type || 'modules';
189	        try {
190	          const graph = await buildDesignGraph(session.workdir, { type });
191	          // Annotate changed nodes
192	          const changeMap = session.lastChangeMap || {};
193	          for (const n of graph.nodes) {
194	            const c = changeMap[n.relPath];
195	            if (c) n.lastChange = c;
196	          }
197	          return json(res, 200, { graph });
198	        } catch (e) {
199	          return json(res, 500, { error: e.message });
200	        }
201	      }
202	
203	      if (rest === '/changes' && req.method === 'GET') {
204	        return json(res, 200, { changes: session.changes });
205	      }
206	
207	      const approveMatch = rest.match(/^\/approve\/([^/]+)$/);
208	      if (approveMatch && req.method === 'POST') {
209	        const body = await readJson(req);
210	        const ok = session.resolveApproval(approveMatch[1], body.decision, body.note);
211	        return json(res, ok ? 200 : 404, { ok });
212	      }
213	
214	      if (rest === '/gitnexus/status' && req.method === 'GET') {
215	        try {
216	          const info = await gitnexus.getStatus(session.workdir);
217	          return json(res, 200, info);
218	        } catch (e) {
219	          return json(res, 500, { error: e.message });
220	        }
221	      }
222	
223	      if (rest === '/gitnexus/analyze' && req.method === 'POST') {
224	        const body = await readJson(req).catch(() => ({}));
225	        // Fire-and-forget: stream lines via SSE, finish event when done.
226	        broadcast('gitnexus:start', { sessionId: id });
227	        gitnexus
228	          .analyze(session.workdir, {
229	            force: !!body.force,
230	            embeddings: !!body.embeddings,
231	            skipAgentsMd: body.skipAgentsMd !== false,
232	            onLine: ({ stream, line }) =>
233	              broadcast('gitnexus:progress', { sessionId: id, stream, line }),
234	          })
235	          .then((r) => broadcast('gitnexus:done', { sessionId: id, code: r.code }))
236	          .catch((e) => broadcast('gitnexus:done', { sessionId: id, error: e.message }));
237	        return json(res, 202, { ok: true });
238	      }
239	
240	      if (rest === '/gitnexus/tool' && req.method === 'POST') {
241	        const body = await readJson(req);
242	        const kind = body.kind || 'tool';
243	        try {
244	          let payload;
245	          if (kind === 'callgraph') payload = await gitnexus.getCallGraph(session.workdir, body.args || {});
246	          else if (kind === 'processes') payload = await gitnexus.getProcesses(session.workdir, body.args || {});
247	          else if (kind === 'cypher')
248	            payload = await gitnexus.cypher(session.workdir, body.query, body.params || {});
249	          else if (kind === 'impact')
250	            payload = await gitnexus.getImpact(session.workdir, body.symbol);
251	          else if (kind === 'tool')
252	            payload = await gitnexus.callTool(session.workdir, body.name, body.args || {});
253	          else return json(res, 400, { error: '未知 kind: ' + kind });
254	          return json(res, 200, { result: payload });
255	        } catch (e) {
256	          return json(res, 500, { error: e.message });
257	        }
258	      }
259	
260	      return json(res, 404, { error: '未知接口' });
261	    }
262	
263	    // Static file serving from public/
264	    let urlPath = pathname === '/' ? '/index.html' : pathname;
265	    if (urlPath.includes('..')) return json(res, 400, { error: 'invalid path' });
266	    const filePath = path.join(PUBLIC_DIR, urlPath);
267	    if (filePath.startsWith(PUBLIC_DIR) && fs.existsSync(filePath) && fs.statSync(filePath).isFile()) {
268	      const ext = path.extname(filePath).toLowerCase();
269	      res.writeHead(200, { 'Content-Type': MIME[ext] || 'application/octet-stream' });
270	      fs.createReadStream(filePath).pipe(res);
271	      return;
272	    }
273	    return json(res, 404, { error: 'not found' });
274	  } catch (e) {
275	    console.error(e);
276	    return json(res, 500, { error: e.message });
277	  }
278	});
279	
280	function json(res, status, body) {
281	  res.writeHead(status, { 'Content-Type': 'application/json; charset=utf-8' });
282	  res.end(JSON.stringify(body));
283	}
284	
285	function readJson(req) {
286	  return new Promise((resolve, reject) => {
287	    let buf = '';
288	    req.on('data', (c) => (buf += c));
289	    req.on('end', () => {
290	      if (!buf) return resolve({});
291	      try {
292	        resolve(JSON.parse(buf));
293	      } catch (e) {
294	        reject(new Error('Invalid JSON: ' + e.message));
295	      }
296	    });
297	    req.on('error', reject);
298	  });
299	}
300	
301	server.listen(PORT, () => {
302	  // eslint-disable-next-line no-console
303	  console.log(`Claude Code Console running at http://localhost:${PORT}`);
304	  console.log(`Working directory: ${process.cwd()}`);
305	  console.log(`Session data dir: ${DATA_DIR}`);
306	});
307	
308	let shuttingDown = false;
309	function shutdown() {
310	  if (shuttingDown) return;
311	  shuttingDown = true;
312	  for (const s of manager.sessions.values()) {
313	    try { s.cancel(); } catch {}
314	  }
315	  // Defer one tick so any in-flight stdout `data` callbacks finish first.
316	  setImmediate(() => {
317	    try { store.flushAll(manager); } finally { process.exit(0); }
318	  });
319	}
320	process.on('SIGINT', shutdown);
321	process.on('SIGTERM', shutdown);
322	process.on('beforeExit', () => store.flushAll(manager));
