131	class Session {
132	  constructor({ id, workdir, name, policyId, bus }) {
133	    this.id = id;
134	    this.workdir = workdir;
135	    this.name = name;
136	    this.policyId = policyId;
137	    this.bus = bus;
138	
139	    this.createdAt = Date.now();
140	    this.endedAt = null;
141	    this.status = 'idle'; // idle | running | waiting | ended | error
142	    this.claudeSessionId = null;
143	
144	    this.turns = []; // { id, prompt, startedAt, endedAt, status }
145	    this.events = []; // chronological log of EVERY event (audit log)
146	    this.tools = []; // tool_use audit records with policy decision
147	    this.changes = []; // per-turn change sets
148	    this.lastChangeMap = {}; // relPath -> { turn, kind }
149	
150	    this.changeTracker = new ChangeTracker(workdir);
151	    this.changeTracker.takeSnapshot();
152	    this.fileBaselines = {}; // relPath -> content snapshot for diff display
153	
154	    this.activeChild = null;
155	    this.activeTurn = null;
156	    this.pendingApprovals = new Map();
157	  }
158	
159	  summary() {
160	    return {
161	      id: this.id,
162	      name: this.name,
163	      workdir: this.workdir,
164	      policyId: this.policyId,
165	      status: this.status,
166	      createdAt: this.createdAt,
167	      endedAt: this.endedAt,
168	      turnCount: this.turns.length,
169	      changeCount: this.changes.reduce((acc, c) => acc + c.files.length, 0),
170	      pendingApprovals: this.pendingApprovals.size,
171	      claudeSessionId: this.claudeSessionId,
172	    };
173	  }
174	
175	  setPolicy(policyId) {
176	    this.policyId = policyId;
177	    this._record({ type: 'policy:changed', policyId });
178	  }
