180	  // ===== Turn execution =====
181	  async sendPrompt(prompt) {
182	    if (this.activeChild) throw new Error('当前会话已有运行中的对话');
183	    const policy = getPolicy(this.policyId);
184	    const turnId = `t${this.turns.length + 1}`;
185	    const turn = {
186	      id: turnId,
187	      prompt,
188	      startedAt: Date.now(),
189	      endedAt: null,
190	      status: 'running',
191	      policyId: policy.id,
192	    };
193	    this.turns.push(turn);
194	    this.activeTurn = turn;
195	
196	    this.status = 'running';
197	    this._record({ type: 'turn:start', turnId, prompt, policyId: policy.id });
198	    this._broadcastSummary();
199	
200	    // Take a snapshot before running so we can diff afterwards.
201	    this.changeTracker.takeSnapshot();
202	
203	    const args = [
204	      '--print',
205	      '--output-format', 'stream-json',
206	      '--verbose',
207	      '--permission-mode', policy.permissionMode,
208	    ];
209	    if (this.claudeSessionId) {
210	      args.push('--resume', this.claudeSessionId);
211	    }
212	    args.push(prompt);
213	
214	    let child;
215	    try {
216	      child = spawn('claude', args, {
217	        cwd: this.workdir,
218	        env: { ...process.env, FORCE_COLOR: '0' },
219	        stdio: ['ignore', 'pipe', 'pipe'],
220	      });
221	    } catch (e) {
222	      this._record({ type: 'turn:error', turnId, error: e.message });
223	      turn.status = 'error';
224	      turn.endedAt = Date.now();
225	      this.status = 'error';
226	      this.activeTurn = null;
227	      this._broadcastSummary();
228	      throw e;
229	    }
230	    this.activeChild = child;
231	
232	    // Pre-capture baselines for any files that may be edited so we can show
233	    // diffs even after Claude writes them.
234	    // We capture lazily on-demand from snapshot keys.
235	
236	    let stdoutBuf = '';
237	    child.stdout.on('data', (chunk) => {
238	      stdoutBuf += chunk.toString('utf8');
239	      let idx;
240	      while ((idx = stdoutBuf.indexOf('\n')) >= 0) {
241	        const line = stdoutBuf.slice(0, idx).trim();
242	        stdoutBuf = stdoutBuf.slice(idx + 1);
243	        if (line) this._handleStreamLine(line);
244	      }
245	    });
246	
247	    let stderrBuf = '';
248	    child.stderr.on('data', (chunk) => {
249	      stderrBuf += chunk.toString('utf8');
250	    });
251	
252	    child.on('error', (err) => {
253	      this._record({ type: 'turn:error', turnId, error: err.message });
254	      this._endTurn('error', err.message);
255	    });
256	
257	    child.on('close', (code) => {
258	      if (stdoutBuf.trim()) this._handleStreamLine(stdoutBuf.trim());
259	      if (code !== 0 && stderrBuf) {
260	        this._record({ type: 'cli:stderr', text: stderrBuf.trim() });
261	      }
262	      this._afterTurnFinish(code === 0 ? 'done' : 'error');
263	    });
264	
265	    return turn;
266	  }
