286	  _handleStreamLine(line) {
287	    let evt;
288	    try {
289	      evt = JSON.parse(line);
290	    } catch {
291	      this._record({ type: 'cli:rawline', text: line });
292	      return;
293	    }
294	
295	    // Capture session id if provided.
296	    if (evt.type === 'system' && evt.subtype === 'init' && evt.session_id) {
297	      this.claudeSessionId = evt.session_id;
298	      this._broadcastSummary();
299	    }
300	
301	    // Surface assistant text + tool uses.
302	    if (evt.type === 'assistant' && evt.message && Array.isArray(evt.message.content)) {
303	      for (const block of evt.message.content) {
304	        if (block.type === 'text' && block.text) {
305	          this._record({
306	            type: 'assistant:text',
307	            turnId: this.activeTurn?.id,
308	            text: block.text,
309	          });
310	        } else if (block.type === 'tool_use') {
311	          this._handleToolUse(block);
312	        } else if (block.type === 'thinking' && block.thinking) {
313	          this._record({
314	            type: 'assistant:thinking',
315	            turnId: this.activeTurn?.id,
316	            text: block.thinking,
317	          });
318	        }
319	      }
320	    } else if (evt.type === 'user' && evt.message && Array.isArray(evt.message.content)) {
321	      for (const block of evt.message.content) {
322	        if (block.type === 'tool_result') {
323	          this._record({
324	            type: 'tool:result',
325	            turnId: this.activeTurn?.id,
326	            tool_use_id: block.tool_use_id,
327	            isError: block.is_error || false,
328	            content: extractText(block.content),
329	          });
330	        }
331	      }
332	    } else if (evt.type === 'result') {
333	      this._record({
334	        type: 'turn:result',
335	        turnId: this.activeTurn?.id,
336	        subtype: evt.subtype,
337	        result: evt.result,
338	        durationMs: evt.duration_ms,
339	        usage: evt.usage,
340	        cost: evt.total_cost_usd,
341	      });
342	    } else if (evt.type === 'system') {
343	      // Forward as raw system event for inspectors.
344	      this._record({
345	        type: 'system',
346	        turnId: this.activeTurn?.id,
347	        subtype: evt.subtype,
348	        raw: evt,
349	      });
350	    } else {
351	      // Unknown — keep raw.
352	      this._record({ type: 'cli:event', raw: evt });
353	    }
354	  }
