356	  _handleToolUse(block) {
357	    const policy = getPolicy(this.policyId);
358	    const decision = evaluateToolUse(policy, block, { workdir: this.workdir });
359	    const record = {
360	      id: block.id,
361	      turnId: this.activeTurn?.id,
362	      tool: block.name,
363	      input: block.input,
364	      decision: decision.decision,
365	      reason: decision.reason,
366	      ruleMatched: decision.rule?.match || null,
367	      timestamp: Date.now(),
