386	  // The user may resolve a pending manual approval from the UI. Because the
387	  // CLI already executed (or was prevented) by --permission-mode, this resolve
388	  // is informational/audit-only. We still track it so the UX is honest.
389	  resolveApproval(toolUseId, decision, note) {
390	    const rec = this.pendingApprovals.get(toolUseId);
391	    if (!rec) return false;
392	    this.pendingApprovals.delete(toolUseId);
393	    rec.decision = decision; // 'auto' (approved) | 'reject'
394	    rec.manualResolution = decision;
