409	  _afterTurnFinish(reason) {
410	    const turn = this.activeTurn;
411	    if (turn) {
412	      turn.status = reason;
413	      turn.endedAt = Date.now();
414	    }
415	    this.activeChild = null;
416	
417	    // Compute file changes for the turn.
418	    const changedFiles = this.changeTracker.diff();
419	    if (changedFiles.length > 0 && turn) {
420	      const enriched = changedFiles.map((c) => {
421	        let beforeContent = this.fileBaselines[c.relPath] ?? null;
422	        let afterContent = null;
423	        if (c.kind !== 'deleted') {
424	          const r = this.changeTracker.readFile(c.relPath);
425	          afterContent = r.content;
426	        }
427	        let diffLines = null;
428	        if (beforeContent != null || afterContent != null) {
429	          diffLines = this.changeTracker.unifiedDiff(c.relPath, beforeContent || '', afterContent || '');
430	        }
431	        // Update baseline for next turn.
432	        if (afterContent != null) this.fileBaselines[c.relPath] = afterContent;
433	        else delete this.fileBaselines[c.relPath];
434	
435	        return {
436	          relPath: c.relPath,
437	          kind: c.kind,
438	          size: c.size,
439	          diff: diffLines,
440	        };
441	      });
442	      const changeSet = {
443	        turnId: turn.id,
444	        timestamp: Date.now(),
445	        files: enriched,
446	      };
447	      this.changes.push(changeSet);
448	      for (const f of enriched) {
449	        this.lastChangeMap[f.relPath] = { turnId: turn.id, kind: f.kind };
450	      }
451	      this._record({ type: 'turn:changes', turnId: turn.id, files: enriched });
452	    } else if (turn) {
453	      this._record({ type: 'turn:changes', turnId: turn.id, files: [] });
454	    }
455	
456	    if (turn) this._record({ type: 'turn:end', turnId: turn.id, status: turn.status });
457	
458	    this.activeTurn = null;
459	    this.status = reason === 'error' ? 'error' : 'idle';
460	    this._broadcastSummary();
461	  }
462	
463	  _record(event) {
464	    const enriched = { id: randomUUID(), ts: Date.now(), ...event };
465	    this.events.push(enriched);
466	    if (this.events.length > MAX_EVENTS) {
467	      this.events.splice(0, this.events.length - MAX_EVENTS);
468	    }
469	    this.bus.emit('session:event', { sessionId: this.id, event: enriched });
470	    this._store?.scheduleSave(this);
471	  }
472	
473	  _broadcastSummary() {
474	    this.bus.emit('session:updated', this.summary());
475	  }
476	}
